  1	import * as React from 'react';
  2	import { ActionGroup, Button } from '@patternfly/react-core';
  3	import { useCustomTranslation } from '../useCustomTranslationHook';
  4	import { ButtonBar } from './ButtonBar';
  5	import CloseButton from './CloseButton';
  6	import '../modals/modal.scss';
  7	
  8	export const ModalTitle: React.FC<ModalTitleProps> = ({
  9	  children,
 10	  className = 'modal-header',
 11	  close,
 12	}) => (
 13	  <div className={className}>
 14	    <h1 className="pf-v6-c-title pf-m-2xl" data-test-id="modal-title">
 15	      {children}
 16	      {close && (
 17	        <CloseButton
 18	          onClick={(e) => {
 19	            e.stopPropagation();
 20	            close(e);
 21	          }}
 22	          additionalClassName="co-close-button--float-right"
 23	        />
 24	      )}
 25	    </h1>
 26	  </div>
 27	);
 28	
 29	export const ModalBody: React.SFC<ModalBodyProps> = ({ children }) => (
 30	  <div className="modal-body">
 31	    <div className="modal-body-content">
 32	      <div className="modal-body-inner-shadow-covers">{children}</div>
 33	    </div>
 34	  </div>
 35	);
 36	
 37	export const ModalFooter: React.SFC<ModalFooterProps> = ({
 38	  message,
 39	  errorMessage,
 40	  inProgress,
 41	  children,
 42	}) => {
 43	  return (
 44	    <ButtonBar
 45	      className="modal-footer"
 46	      errorMessage={errorMessage}
 47	      infoMessage={message}
 48	      inProgress={inProgress}
 49	    >
 50	      {children as React.ReactChild}
 51	    </ButtonBar>
 52	  );
 53	};
 54	
 55	export const ModalSubmitFooter: React.SFC<ModalSubmitFooterProps> = ({
 56	  message,
 57	  errorMessage,
 58	  inProgress,
 59	  cancel,
 60	  submitText,
 61	  cancelText,
 62	  submitDisabled,
 63	  submitDanger,
 64	  resetText,
 65	  reset,
 66	}) => {
 67	  const { t } = useCustomTranslation();
 68	  const onCancelClick = (e) => {
 69	    e.stopPropagation();
 70	    cancel(e);
 71	  };
 72	
 73	  const onResetClick = (e) => {
 74	    e.stopPropagation();
 75	    reset(e);
 76	  };
 77	
 78	  return (
 79	    <ModalFooter
 80	      inProgress={inProgress}
 81	      errorMessage={errorMessage}
 82	      message={message}
 83	    >
 84	      <ActionGroup className="pf-v6-c-form pf-v6-c-form__actions--right pf-v6-c-form__group--no-top-margin">
 85	        {reset && (
 86	          <Button
 87	            variant="link"
 88	            isInline
 89	            onClick={onResetClick}
 90	            id="reset-action"
 91	          >
 92	            {resetText || t('Reset')}
 93	          </Button>
 94	        )}
 95	        <Button
 96	          type="button"
 97	          variant="secondary"
 98	          data-test-id="modal-cancel-action"
 99	          onClick={onCancelClick}
100	          aria-label={t('Cancel')}
101	        >
102	          {cancelText || t('Cancel')}
103	        </Button>
104	        {submitDanger ? (
105	          <Button
106	            type="submit"
107	            variant="danger"
108	            isDisabled={submitDisabled}
109	            data-test="confirm-action"
110	            id="confirm-action"
111	          >
112	            {submitText}
113	          </Button>
114	        ) : (
115	          <Button
116	            type="submit"
117	            variant="primary"
118	            isDisabled={submitDisabled}
119	            data-test="confirm-action"
120	            id="confirm-action"
121	          >
122	            {submitText}
123	          </Button>
124	        )}
125	      </ActionGroup>
126	    </ModalFooter>
127	  );
128	};
129	
130	export type ModalTitleProps = {
131	  className?: string;
132	  close?: (e: React.SyntheticEvent<any, Event>) => void;
133	};
134	
135	export type ModalBodyProps = {
136	  className?: string;
137	};
138	
139	export type ModalFooterProps = {
140	  message?: string;
141	  errorMessage?: React.ReactNode;
142	  inProgress: boolean;
143	};
144	
145	export type ModalSubmitFooterProps = {
146	  message?: string;
147	  errorMessage?: string;
148	  inProgress: boolean;
149	  cancel: (e: React.SyntheticEvent<any, Event>) => void;
150	  cancelText?: React.ReactNode;
151	  resetText?: React.ReactNode;
152	  reset?: (e: React.SyntheticEvent<any, Event>) => void;
153	  submitText: React.ReactNode;
154	  submitDisabled?: boolean;
155	  submitDanger?: boolean;
156	};
157	
158	export type ModalComponentProps = {
159	  cancel?: () => void;
160	  close?: () => void;
161	};

